const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task1_searchParams') || 'null');
const providers = JSON.parse(localStorage.getItem('providers') || '[]');
const services = JSON.parse(localStorage.getItem('provider_services') || '[]');
const bookings = JSON.parse(localStorage.getItem('appointment_bookings') || '[]');

function getServiceMinPrice(s) {
  if (!s) return Infinity;
  const prices = [];
  if (typeof s.base_price === 'number') prices.push(s.base_price);
  if (typeof s.min_price === 'number') prices.push(s.min_price);
  if (typeof s.max_price === 'number') prices.push(s.max_price);
  if (!prices.length) return Infinity;
  return Math.min.apply(null, prices);
}

function getLocationZipPrefix(sp) {
  if (!sp || !sp.location_text_used) return null;
  const txt = String(sp.location_text_used).trim();
  const m = txt.match(/\d{5}/);
  return m ? m[0].slice(0, 3) : null;
}

const zipPrefix = getLocationZipPrefix(searchParams) || '100';
const maxPriceAllowed = (searchParams && searchParams.price_filter && typeof searchParams.price_filter.max_price === 'number') ? searchParams.price_filter.max_price : 200;
const ratingMin = (searchParams && typeof searchParams.rating_min === 'number') ? searchParams.rating_min : 4.5;

// Find qualifying iPhone 12 screen repair services under price cap near ZIP and with required rating
const qualifying = services
  .filter(s => s && s.service_code === 'smartphone_screen_repair' && s.device_brand === 'Apple' && s.device_model === 'iPhone 12')
  .map(s => {
    const p = providers.find(pr => pr.id === s.providerId);
    if (!p) return null;
    // Location: same 3-digit ZIP prefix
    if ((p.postal_code || '').slice(0, 3) !== zipPrefix) return null;
    if (typeof p.rating_average === 'number' && p.rating_average < ratingMin) return null;
    const minPrice = getServiceMinPrice(s);
    if (minPrice > maxPriceAllowed) return null;
    return { provider: p, service: s, minPrice };
  })
  .filter(x => !!x);

let best = null;
qualifying.forEach(q => {
  if (!best) {
    best = q;
  } else if (q.provider.rating_average > best.provider.rating_average) {
    best = q;
  } else if (q.provider.rating_average === best.provider.rating_average && q.provider.rating_count > best.provider.rating_count) {
    best = q;
  }
});

function isOn15thAt3pm(iso) {
  if (!iso) return false;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return false;
  return d.getUTCDate() === 15 && d.getUTCHours() === 15 && d.getUTCMinutes() === 0;
}

// Checkpoint 1 (0.30): User searched with filters matching task requirements
const cp1Passed = !!(searchParams &&
  searchParams.service_code === 'smartphone_screen_repair' &&
  (!searchParams.distance_miles_max || searchParams.distance_miles_max <= 10) &&
  (!searchParams.rating_min || searchParams.rating_min >= 4.5) &&
  searchParams.price_filter && typeof searchParams.price_filter.max_price === 'number' && searchParams.price_filter.max_price <= 200 &&
  searchParams.sort_by === 'rating_desc' &&
  searchParams.location_text_used && String(searchParams.location_text_used).trim().startsWith('10001')
);
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Find a booking that matches iPhone 12 screen repair under $200 on 15th at 3 PM
let qualifyingBooking = null;
for (const b of bookings) {
  if (!b || b.booking_type !== 'in_store') continue;
  if (!isOn15thAt3pm(b.appointment_datetime)) continue;
  const s = services.find(sv => sv.id === b.providerServiceId);
  const p = providers.find(pr => pr.id === b.providerId);
  if (!s || !p) continue;
  if (s.service_code !== 'smartphone_screen_repair' || s.device_brand !== 'Apple' || s.device_model !== 'iPhone 12') continue;
  const minPrice = getServiceMinPrice(s);
  if (minPrice > 200) continue;
  qualifyingBooking = b;
  break;
}

// Checkpoint 2 (0.30): User created an appropriate appointment booking (correct service and time)
const cp2Passed = !!qualifyingBooking;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// Checkpoint 3 (0.40): Appointment is with the highest-rated qualifying provider
const cp3Passed = !!(qualifyingBooking && best && qualifyingBooking.providerId === best.provider.id);
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task2_searchParams') || 'null');
const providers = JSON.parse(localStorage.getItem('providers') || '[]');
const services = JSON.parse(localStorage.getItem('provider_services') || '[]');
const quotes = JSON.parse(localStorage.getItem('quote_requests') || '[]');

function getServiceMinPrice(s) {
  if (!s) return Infinity;
  const prices = [];
  if (typeof s.base_price === 'number') prices.push(s.base_price);
  if (typeof s.min_price === 'number') prices.push(s.min_price);
