function providerNearSF(p) {
  if (!p) return false;
  if (p.city && p.state && p.city.toLowerCase() === 'san francisco' && p.state.toLowerCase() === 'ca') return true;
  return (p.postal_code || '').startsWith('941');
}

const maxPriceAllowed = (searchParams && searchParams.price_filter && typeof searchParams.price_filter.max_price === 'number') ? searchParams.price_filter.max_price : 120;

// All qualifying laptop battery replacement services under price cap near SF
const qualifying = services
  .filter(s => s && s.service_code === 'laptop_battery_replacement' && s.device_type === 'laptop')
  .map(s => {
    const p = providers.find(pr => pr.id === s.providerId);
    if (!p) return null;
    if (!providerNearSF(p)) return null;
    const minPrice = getServiceMinPrice(s);
    if (minPrice > maxPriceAllowed) return null;
    return { provider: p, service: s, minPrice };
  })
  .filter(x => !!x);

let cheapest = null;
qualifying.forEach(q => {
  if (!cheapest || q.minPrice < cheapest.minPrice) {
    cheapest = q;
  }
});

// Checkpoint 1 (0.30): Search used correct filters
const cp1Passed = !!(searchParams &&
  searchParams.service_code === 'laptop_battery_replacement' &&
  (!searchParams.distance_miles_max || searchParams.distance_miles_max <= 25) &&
  searchParams.price_filter && typeof searchParams.price_filter.max_price === 'number' && searchParams.price_filter.max_price <= 120 &&
  searchParams.sort_by === 'price_asc' &&
  searchParams.location_text_used && /san francisco/i.test(String(searchParams.location_text_used))
);
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Find a quote request that matches a qualifying laptop battery replacement service
let qualifyingQuote = null;
for (const q of quotes) {
  const s = services.find(sv => sv.id === q.providerServiceId);
  const p = providers.find(pr => pr.id === q.providerId);
  if (!s || !p) continue;
  if (s.service_code !== 'laptop_battery_replacement' || s.device_type !== 'laptop') continue;
  if (!providerNearSF(p)) continue;
  const minPrice = getServiceMinPrice(s);
  if (minPrice > 120) continue;
  if (!q.problem_description || !q.problem_description.trim()) continue;
  qualifyingQuote = q;
  break;
}

// Checkpoint 2 (0.30): User sent a quote request for a qualifying laptop battery replacement under $120 near SF
const cp2Passed = !!qualifyingQuote;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// Checkpoint 3 (0.40): Quote was sent to the cheapest qualifying provider/service
const cp3Passed = !!(qualifyingQuote && cheapest && qualifyingQuote.providerId === cheapest.provider.id && qualifyingQuote.providerServiceId === cheapest.service.id);
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

