}

const maxPriceAllowed = (searchParams && searchParams.price_filter && typeof searchParams.price_filter.max_price === 'number') ? searchParams.price_filter.max_price : 150;
const ratingMin = (searchParams && typeof searchParams.rating_min === 'number') ? searchParams.rating_min : 4.0;

// All qualifying PS5 HDMI port repair services
const ps5Services = services
  .filter(s => s && s.service_code === 'console_hdmi_port_repair' && s.device_brand === 'Sony' && s.device_model === 'PlayStation 5')
  .map(s => {
    const p = providers.find(pr => pr.id === s.providerId);
    if (!p) return null;
    if (typeof p.rating_average === 'number' && p.rating_average < ratingMin) return null;
    const minPrice = getServiceMinPrice(s);
    if (minPrice > maxPriceAllowed) return null;
    return { provider: p, service: s };
  })
  .filter(x => !!x);

// Unique qualifying providers
const qualifyingProvidersMap = {};
ps5Services.forEach(q => { qualifyingProvidersMap[q.provider.id] = q.provider; });
const qualifyingProviders = Object.values(qualifyingProvidersMap);

// Compute provider with longest warranty (consider provider.max_warranty_months and service.warranty_months)
let bestProvider = null;
let bestWarranty = -1;
qualifyingProviders.forEach(p => {
  let maxW = typeof p.max_warranty_months === 'number' ? p.max_warranty_months : 0;
  services.filter(s => s.providerId === p.id && s.service_code === 'console_hdmi_port_repair').forEach(s => {
    if (typeof s.warranty_months === 'number' && s.warranty_months > maxW) maxW = s.warranty_months;
  });
  if (maxW > bestWarranty) {
    bestWarranty = maxW;
    bestProvider = p;
  }
});

const compareList = Array.isArray(compareLists) && compareLists.length ? compareLists[0] : null;
const compareIds = compareList && Array.isArray(compareList.providerIds) ? compareList.providerIds : [];

const qualifyingComparedIds = compareIds.filter(id => qualifyingProviders.some(p => p.id === id));

// Checkpoint 1 (0.30): Search used correct filters for console HDMI port repair under $150 with rating ≥4
const cp1Passed = !!(searchParams &&
  searchParams.service_code === 'console_hdmi_port_repair' &&
  (!searchParams.price_filter || !searchParams.price_filter.max_price || searchParams.price_filter.max_price <= 150) &&
  (!searchParams.rating_min || searchParams.rating_min >= 4.0)
);
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Checkpoint 2 (0.30): Compare list contains at least two qualifying PS5 HDMI providers
const cp2Passed = qualifyingComparedIds.length >= 2;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// Checkpoint 3 (0.40): User favorited the provider with the longest warranty among qualifying services
const cp3Passed = !!(bestProvider && favorites.some(f => f && f.providerId === bestProvider.id));
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task4_searchParams') || 'null');
const providers = JSON.parse(localStorage.getItem('providers') || '[]');
const services = JSON.parse(localStorage.getItem('provider_services') || '[]');
const hours = JSON.parse(localStorage.getItem('provider_opening_hours') || '[]');
const homeVisits = JSON.parse(localStorage.getItem('home_visit_requests') || '[]');

function getServiceMinPrice(s) {
  if (!s) return Infinity;
  const prices = [];
  if (typeof s.base_price === 'number') prices.push(s.base_price);
  if (typeof s.min_price === 'number') prices.push(s.min_price);
  if (typeof s.max_price === 'number') prices.push(s.max_price);
  if (!prices.length) return Infinity;
  return Math.min.apply(null, prices);
}

function providerMatchesLocation(p, sp) {
  if (!p) return false;
  if (!sp || !sp.location_text_used) {
    return (p.city && /chicago/i.test(p.city)) || (p.postal_code || '').startsWith('606');
  }
  const txt = String(sp.location_text_used).toLowerCase();
  const zipMatch = txt.match(/\d{5}/);
  if (zipMatch) {
    const prefix = zipMatch[0].slice(0, 3);
    return (p.postal_code || '').slice(0, 3) === prefix;
  }
  if (/chicago/.test(txt)) return true;
  return false;
}

function providerOpenSatAfter5(p) {
  const hs = hours.filter(h => h.providerId === p.id && h.day_of_week === 'saturday' && !h.is_closed);
  if (!hs.length) return false;
  return hs.some(h => h.is_open_24_hours || (h.close_time && h.close_time >= '17:00'));
}

function hasNoDiagnosticFee(p, s) {
  if (!p && !s) return false;
  if (p && (p.has_no_diagnostic_fee === true || p.default_diagnostic_fee === 0)) return true;
  if (s && (s.has_no_diagnostic_fee === true || s.diagnostic_fee_amount === 0)) return true;
  return false;
}

// Qualifying washing machine home-visit services
const qualifying = services
  .filter(s => s && s.service_code === 'washing_machine_repair' && s.device_type === 'home_appliance' && s.is_home_visit_available)
  .map(s => {
    const p = providers.find(pr => pr.id === s.providerId);
    if (!p) return null;
    if (!p.offers_home_visit) return null;
    if (!providerMatchesLocation(p, searchParams)) return null;
    if (!providerOpenSatAfter5(p)) return null;
    if (!hasNoDiagnosticFee(p, s)) return null;
    return { provider: p, service: s };
  })
  .filter(x => !!x);

let topProvider = null;
qualifying.forEach(q => {
  const p = q.provider;
  if (!topProvider || p.rating_average > topProvider.rating_average || (p.rating_average === topProvider.rating_average && p.rating_count > topProvider.rating_count)) {
    topProvider = p;
  }
});

function isSaturdayEvening(dtStr) {
  if (!dtStr) return false;
  const d = new Date(dtStr);
  if (isNaN(d.getTime())) return false;
  const day = d.getUTCDay(); // 6 = Saturday
  const hour = d.getUTCHours();
  return day === 6 && hour >= 17;
}

// Checkpoint 1 (0.30): Search used correct filters (home visit, no diagnostic fee, Saturday after 5 PM near 60601)
const av = searchParams && searchParams.availability_filters;
const visit = searchParams && searchParams.visit_type_filters;
const fee = searchParams && searchParams.fee_filters;
const cp1Passed = !!(searchParams &&
  searchParams.service_code === 'washing_machine_repair' &&
  (!searchParams.distance_miles_max || searchParams.distance_miles_max <= 20) &&
  visit && visit.home_visit === true &&
  fee && fee.require_no_diagnostic_fee === true &&
  av && av.open_on_day_of_week === 'saturday' && av.close_after_time && av.close_after_time >= '17:00' &&
  searchParams.sort_by === 'rating_desc' &&
  searchParams.location_text_used && (String(searchParams.location_text_used).startsWith('60601') || /chicago/i.test(String(searchParams.location_text_used)))
);
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Find a home visit request that matches a qualifying provider/service and Saturday evening time
let qualifyingRequest = null;
for (const r of homeVisits) {
  const s = services.find(sv => sv.id === r.providerServiceId);
  const p = providers.find(pr => pr.id === r.providerId);
  if (!s || !p) continue;
  if (s.service_code !== 'washing_machine_repair' || !s.is_home_visit_available) continue;
  if (!hasNoDiagnosticFee(p, s)) continue;
  if (!providerMatchesLocation(p, searchParams)) continue;
  if (!isSaturdayEvening(r.preferred_datetime)) continue;
  qualifyingRequest = r;
  break;
}

// Checkpoint 2 (0.30): User submitted a qualifying home visit request for Saturday evening
const cp2Passed = !!qualifyingRequest;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// Checkpoint 3 (0.40): Request is with the highest-rated qualifying provider
const cp3Passed = !!(qualifyingRequest && topProvider && qualifyingRequest.providerId === topProvider.id);
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const profile = JSON.parse(localStorage.getItem('profile') || 'null');
const reviews = JSON.parse(localStorage.getItem('reviews') || '[]');
const providers = JSON.parse(localStorage.getItem('providers') || '[]');
const services = JSON.parse(localStorage.getItem('provider_services') || '[]');

function providerHasDiagnosticFee(p) {
  if (!p) return false;
  if (p.has_free_diagnostic === true || p.has_no_diagnostic_fee === true) return false;
  if (typeof p.default_diagnostic_fee === 'number' && p.default_diagnostic_fee > 0) return true;
  // Also consider service-level diagnostic fees
  const svc = services.filter(s => s.providerId === p.id && s.device_type === 'smartphone');
  return svc.some(s => s.has_free_diagnostic !== true && s.has_no_diagnostic_fee !== true && typeof s.diagnostic_fee_amount === 'number' && s.diagnostic_fee_amount > 0);
}

function providerOffersSmartphone(p) {
  return services.some(s => s.providerId === p.id && (s.device_type === 'smartphone' || s.service_code === 'smartphone_repair' || s.service_code === 'smartphone_screen_repair'));
}

// Qualifying smartphone providers in New York that charge a diagnostic fee
const qualifyingProviders = providers.filter(p => {
  if (!p) return false;
  if (!providerOffersSmartphone(p)) return false;
  if (!p.city || p.city.toLowerCase() !== 'new york' || !p.state || p.state.toLowerCase() !== 'ny') return false;
  if (!providerHasDiagnosticFee(p)) return false;
  return true;
});

// Any 5-star smartphone repair review with a meaningful comment for a qualifying provider
const matchingReviews = reviews.filter(r => {
  if (!r || r.rating !== 5) return false;
  if (!r.comment || r.comment.trim().length < 10) return false;
  if (r.visit_type && r.visit_type !== 'smartphone_repair') return false;
  const p = providers.find(pr => pr.id === r.providerId);
  if (!p) return false;
  return qualifyingProviders.some(qp => qp.id === p.id);
});

// Checkpoint 1 (0.40): User profile has been meaningfully filled (name, email, or phone)
const cp1Passed = !!(profile && (
  (profile.full_name && profile.full_name.trim().length > 0) ||
  (profile.email && profile.email.trim().length > 0) ||
  (profile.phone && profile.phone.trim().length > 0)
));
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// Checkpoint 2 (0.60): User left at least one 5-star smartphone repair review with a meaningful comment for a qualifying NY provider that charges a diagnostic fee
const cp2Passed = matchingReviews.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

