  searchParams.service_code === 'tablet_charging_port_repair' &&
  (!searchParams.price_filter || !searchParams.price_filter.max_price || searchParams.price_filter.max_price <= 90) &&
  (!searchParams.rating_min || searchParams.rating_min >= 4.0) &&
