const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task8_searchParams') || 'null');
const messages = JSON.parse(localStorage.getItem('provider_messages') || '[]');
const providers = JSON.parse(localStorage.getItem('providers') || '[]');
const services = JSON.parse(localStorage.getItem('provider_services') || '[]');

function getServiceMinPrice(s) {
  if (!s) return Infinity;
  const prices = [];
  if (typeof s.base_price === 'number') prices.push(s.base_price);
  if (typeof s.min_price === 'number') prices.push(s.min_price);
  if (typeof s.max_price === 'number') prices.push(s.max_price);
  if (!prices.length) return Infinity;
  return Math.min.apply(null, prices);
}

function hasFreeDiagnostic(p, s) {
  if (p && p.has_free_diagnostic) return true;
  if (s && s.has_free_diagnostic) return true;
  return false;
}

function hasNoFixNoFee(p, s) {
  if (p && p.has_no_fix_no_fee) return true;
  if (s && s.has_no_fix_no_fee) return true;
  return false;
}

const maxPriceAllowed = (searchParams && searchParams.price_filter && typeof searchParams.price_filter.max_price === 'number') ? searchParams.price_filter.max_price : 400;
const ratingMin = (searchParams && typeof searchParams.rating_min === 'number') ? searchParams.rating_min : 4.0;

// Qualifying laptop data recovery services
const qualifying = services
  .filter(s => s && s.service_code === 'laptop_data_recovery')
  .map(s => {
    const p = providers.find(pr => pr.id === s.providerId);
    if (!p) return null;
    if (typeof p.rating_average === 'number' && p.rating_average < ratingMin) return null;
    const minPrice = getServiceMinPrice(s);
    if (minPrice > maxPriceAllowed) return null;
    if (!hasFreeDiagnostic(p, s)) return null;
    if (!hasNoFixNoFee(p, s)) return null;
    return { provider: p, service: s };
  })
  .filter(x => !!x);

// Highest-rated qualifying provider
let topProvider = null;
qualifying.forEach(q => {
  const p = q.provider;
  if (!topProvider || p.rating_average > topProvider.rating_average || (p.rating_average === topProvider.rating_average && p.rating_count > topProvider.rating_count)) {
    topProvider = p;
  }
});

// Checkpoint 1 (0.30): Search used correct filters (laptop data recovery, free diagnostic, no-fix-no-fee, under $400, rating sort)
const fee = searchParams && searchParams.fee_filters;
const cp1Passed = !!(searchParams &&
  searchParams.service_code === 'laptop_data_recovery' &&
  (!searchParams.price_filter || !searchParams.price_filter.max_price || searchParams.price_filter.max_price <= 400) &&
  (!searchParams.rating_min || searchParams.rating_min >= 4.0) &&
  fee && fee.require_free_diagnostic === true && fee.require_no_fix_no_fee === true &&
  searchParams.sort_by === 'rating_desc'
);
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Find a message sent to a qualifying provider that asks about turnaround time
let qualifyingMessage = null;
for (const m of messages) {
  const p = providers.find(pr => pr.id === m.providerId);
  if (!p) continue;
  if (!qualifying.some(q => q.provider.id === p.id)) continue;
  const text = ((m.subject || '') + ' ' + (m.message || '')).toLowerCase();
  const mentionsDataRecovery = text.includes('data') && text.includes('recover');
  const mentionsTime = text.includes('time') || text.includes('turnaround') || text.includes('how long');
  if (!mentionsDataRecovery || !mentionsTime) continue;
  qualifyingMessage = m;
  break;
}

// Checkpoint 2 (0.30): User sent a message to a qualifying laptop data recovery provider asking about turnaround time
const cp2Passed = !!qualifyingMessage;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// Checkpoint 3 (0.40): Message was sent to the highest-rated qualifying provider
const cp3Passed = !!(qualifyingMessage && topProvider && qualifyingMessage.providerId === topProvider.id);
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
